#!/bin/sh
# cargo-loco-generate-scaffold/generate.sh
#
# Generator script for Loco scaffolding.
#
# Run from inside a fresh Loco project (one created via
# `loco new --name <form-slug> --db postgres --bg async --assets serverside`)
# to scaffold every CRUD resource for this form. Tables are scaffolded in the
# same order as the form's sql-migrations/ so that FK targets already exist
# when referencing tables are created.
#
# Generated by bin/generate-cargo-loco-scaffold.py from sql-migrations/*.sql.
# Do not edit by hand — re-run the generator after changing the SQL migrations.

set -euf


echo "Scaffolding systematic-coronary-risk-evaluation-2-diabetes (14 tables)..."

cargo loco generate scaffold patient \
    full_name:string! \
    date_of_birth:date! \
    sex:string! \
    nhs_number:string^ \
    height_cm:double \
    weight_kg:double \
    ethnicity:string! \
    --htmx

cargo loco generate scaffold assessment \
    patient:references \
    status:string! \
    --htmx

cargo loco generate scaffold assessment_diabetes_history \
    assessment:references \
    diabetes_type:string! \
    age_at_diagnosis:int \
    diabetes_duration_years:int \
    hba1c_value:double \
    hba1c_unit:string! \
    fasting_glucose:double \
    diabetes_treatment:string! \
    insulin_duration_years:int \
    --htmx

cargo loco generate scaffold assessment_cardiovascular_history \
    assessment:references \
    previous_mi:string! \
    previous_stroke:string! \
    previous_tia:string! \
    peripheral_arterial_disease:string! \
    heart_failure:string! \
    atrial_fibrillation:string! \
    family_cvd_history:string! \
    family_cvd_details:text! \
    current_chest_pain:string! \
    current_dyspnoea:string! \
    --htmx

cargo loco generate scaffold assessment_blood_pressure \
    assessment:references \
    systolic_bp:int \
    diastolic_bp:int \
    on_antihypertensive:string! \
    number_of_bp_medications:int \
    bp_at_target:string! \
    home_bp_monitoring:string! \
    --htmx

cargo loco generate scaffold assessment_lipid_profile \
    assessment:references \
    total_cholesterol:double \
    hdl_cholesterol:double \
    ldl_cholesterol:double \
    triglycerides:double \
    non_hdl_cholesterol:double \
    on_statin:string! \
    statin_name:string! \
    on_other_lipid_therapy:string! \
    --htmx

cargo loco generate scaffold assessment_renal_function \
    assessment:references \
    egfr:int \
    creatinine:int \
    urine_acr:double \
    proteinuria:string! \
    ckd_stage:string! \
    --htmx

cargo loco generate scaffold assessment_lifestyle_factors \
    assessment:references \
    smoking_status:string! \
    cigarettes_per_day:int \
    years_since_quit:int \
    alcohol_units_per_week:int \
    physical_activity:string! \
    diet_quality:string! \
    bmi:double \
    waist_circumference_cm:double \
    --htmx

cargo loco generate scaffold assessment_current_medications \
    assessment:references \
    metformin:string! \
    sglt2_inhibitor:string! \
    glp1_agonist:string! \
    sulfonylurea:string! \
    dpp4_inhibitor:string! \
    insulin:string! \
    ace_inhibitor_or_arb:string! \
    antiplatelet:string! \
    anticoagulant:string! \
    other_medications:text! \
    --htmx

cargo loco generate scaffold assessment_complications_screening \
    assessment:references \
    retinopathy_status:string! \
    last_eye_screening_date:date \
    neuropathy_symptoms:string! \
    monofilament_test:string! \
    foot_pulses:string! \
    foot_ulcer_history:string! \
    ankle_brachial_index:double \
    erectile_dysfunction:string! \
    --htmx

cargo loco generate scaffold assessment_risk_summary \
    assessment:references \
    risk_region:string! \
    additional_risk_factors:text! \
    clinical_notes:text! \
    agreed_treatment_targets:text! \
    follow_up_interval:string! \
    --htmx

cargo loco generate scaffold grading_result \
    assessment:references \
    risk_category:string! \
    graded_at:ts! \
    --htmx

cargo loco generate scaffold grading_fired_rule \
    grading_result:references \
    rule_id:string! \
    category:string! \
    description:text! \
    risk_level:string! \
    --htmx

cargo loco generate scaffold grading_additional_flag \
    grading_result:references \
    flag_id:string! \
    category:string! \
    message:text! \
    priority:string! \
    --htmx

echo "Done."
